     5→//! Parade command - Display comprehensive Heat status for project review
     6→//!
     7→//! Implements both heat view (Firemark) and pace view (Coronet).
     8→
     9→use crate::jjrf_favor::jjrf_Firemark as Firemark;
    10→use crate::jjrf_favor::jjrf_Coronet as Coronet;
    11→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_Heat as Heat, jjrg_HeatStatus as HeatStatus, jjrg_PaceState as PaceState};
    12→use crate::jjrp_print::{jjrp_Table, jjrp_Column, jjrp_Align};
    13→use crate::jjrq_query::{jjrq_files_for_pace, jjrq_file_touches_for_heat};
    14→use std::collections::BTreeMap;
    15→use std::fs;
    16→
    17→/// Arguments for jjx_parade command
    18→#[derive(clap::Args, Debug)]
    19→pub struct jjrpd_ParadeArgs {
    20→    /// Path to the Gallops JSON file
    21→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
    22→    pub file: std::path::PathBuf,
    23→
    24→    /// Target: Firemark (heat view) or Coronet (pace view). If omitted, uses first racing heat.
    25→    pub target: Option<String>,
    26→
    27→    /// Show paddock and full specs (heat mode only)
    28→    #[arg(long)]
    29→    pub full: bool,
    30→
    31→    /// Show only remaining paces (exclude complete/abandoned)
    32→    #[arg(long)]
    33→    pub remaining: bool,
    34→
    35→    /// Show file-touch bitmap (which paces touched which files)
    36→    #[arg(long)]
    37→    pub files: bool,
    38→}
