    40→/// Run the parade command - display comprehensive Heat status
    41→pub fn jjrpd_run_parade(args: jjrpd_ParadeArgs) -> i32 {
    42→    let gallops = match Gallops::jjrg_load(&args.file) {
    43→        Ok(g) => g,
    44→        Err(e) => {
    45→            eprintln!("jjx_parade: error: {}", e);
    46→            return 1;
    47→        }
    48→    };
    49→
    50→    // Resolve target: use provided value or auto-select first racing heat
    51→    let target = match args.target {
    52→        Some(t) => t,
    53→        None => {
    54→            // Load gallops to resolve default heat
    55→            match zjjrpd_resolve_default_heat(&gallops) {
    56→                Ok(fm) => fm,
    57→                Err(e) => {
    58→                    eprintln!("jjx_parade: error: {}", e);
    59→                    return 1;
    60→                }
    61→            }
    62→        }
    63→    };
    64→
    65→    // Determine target type by length
    66→    let target_str = target.strip_prefix('₢').or_else(|| target.strip_prefix('₣')).unwrap_or(&target);
    67→
    68→    if target_str.len() == 5 {
    69→        // Coronet - pace view
    70→        let coronet = match Coronet::jjrf_parse(&target) {
    71→            Ok(c) => c,
    72→            Err(e) => {
    73→                eprintln!("jjx_parade: error: {}", e);
    74→                return 1;
    75→            }
    76→        };
    77→
    78→        // Extract parent firemark
    79→        let firemark = coronet.jjrf_parent_firemark();
    80→        let heat_key = firemark.jjrf_display();
    81→        let heat = match gallops.heats.get(&heat_key) {
    82→            Some(h) => h,
    83→            None => {
    84→                eprintln!("jjx_parade: error: Heat '{}' not found", heat_key);
    85→                return 1;
    86→            }
    87→        };
    88→
    89→        // Find pace
    90→        let coronet_key = coronet.jjrf_display();
    91→        let pace = match heat.paces.get(&coronet_key) {
    92→            Some(p) => p,
    93→            None => {
    94→                eprintln!("jjx_parade: error: Pace '{}' not found in Heat '{}'", coronet_key, heat_key);
    95→                return 1;
    96→            }
    97→        };
    98→
    99→        // Display tack history - iterate in reverse order (oldest first)
   100→        if !pace.tacks.is_empty() {
   101→            // Print header with current state from tacks[0]
   102→            let current_tack = &pace.tacks[0];
   103→            println!("Pace: {} ({})", current_tack.silks, coronet_key);
   104→            println!("Heat: {}", heat_key);
   105→
   106→            // Show work files touched by this pace's commits
   107→            match jjrq_files_for_pace(firemark.jjrf_as_str(), &coronet_key) {
   108→                Ok(files) if !files.is_empty() => {
   109→                    println!("Work files: {}", files.join(", "));
   110→                }
   111→                _ => {}
   112→            }
   113→            println!();
   114→
   115→            // Iterate tacks in reverse order (oldest first)
   116→            for (index, tack) in pace.tacks.iter().rev().enumerate() {
   117→                let state_str = zjjrpd_pace_state_str(&tack.state);
   118→                let basis_str = if tack.basis == "0000000" {
   119→                    "(no basis)".to_string()
   120→                } else {
   121→                    tack.basis.clone()
   122→                };
   123→
   124→                println!("[{}] {} (basis: {})", index, state_str, basis_str);
   125→                println!("    Silks: {}", tack.silks);
   126→                if let Some(ref direction) = tack.direction {
   127→                    println!("    Direction: {}", direction);
   128→                }
   129→                println!();
   130→                // Indent spec text
   131→                for line in tack.text.lines() {
   132→                    println!("    {}", line);
   133→                }
   134→                println!();
   135→            }
   136→        }
   137→    } else if target_str.len() == 2 {
   138→        // Firemark - heat view
   139→        let firemark = match Firemark::jjrf_parse(&target) {
   140→            Ok(fm) => fm,
   141→            Err(e) => {
   142→                eprintln!("jjx_parade: error: {}", e);
   143→                return 1;
   144→            }
   145→        };
   146→
   147→        let heat_key = firemark.jjrf_display();
   148→        let heat = match gallops.heats.get(&heat_key) {
   149→            Some(h) => h,
   150→            None => {
   151→                eprintln!("jjx_parade: error: Heat '{}' not found", heat_key);
   152→                return 1;
   153→            }
   154→        };
   155→
   156→        if args.files {
   157→            return zjjrpd_print_file_bitmap(&firemark, heat);
   158→        } else if args.full {
   159→            // Full view: paddock + all specs
   160→            let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   161→                Ok(content) => content,
   162→                Err(e) => {
   163→                    eprintln!("jjx_parade: error reading paddock file '{}': {}", heat.paddock_file, e);
   164→                    return 1;
   165→                }
   166→            };
   167→
   168→            let status_str = match heat.status {
   169→                HeatStatus::Racing => "racing",
   170→                HeatStatus::Stabled => "stabled",
   171→                HeatStatus::Retired => "retired",
   172→            };
   173→
   174→            println!("Heat: {} ({})", heat.silks, heat_key);
   175→            println!("Status: {}", status_str);
   176→            println!("Created: {}", heat.creation_time);
   177→            println!();
   178→            println!("## Paddock");
   179→            println!();
   180→            println!("{}", paddock_content);
   181→            println!();
   182→            println!("## Paces");
   183→            println!();
   184→
   185→            for coronet_key in &heat.order {
   186→                if let Some(pace) = heat.paces.get(coronet_key) {
   187→                    if let Some(tack) = pace.tacks.first() {
   188→                        // Skip complete/abandoned if --remaining
   189→                        if args.remaining && (tack.state == PaceState::Complete || tack.state == PaceState::Abandoned) {
   190→                            continue;
   191→                        }
   192→                        let state_str = zjjrpd_pace_state_str(&tack.state);
   193→                        println!("### {} ({}) [{}]", tack.silks, coronet_key, state_str);
   194→                        println!();
   195→                        println!("{}", tack.text);
   196→                        if let Some(ref direction) = tack.direction {
   197→                            println!();
   198→                            println!("**Direction:** {}", direction);
   199→                        }
   200→                        println!();
   201→                    }
   202→                }
   203→            }
   204→        } else {
   205→            // List view: numbered paces
   206→            // If --remaining, output markdown format
   207→            if args.remaining {
   208→                let mut complete_count = 0;
   209→                let mut abandoned_count = 0;
   210→                let mut rough_count = 0;
   211→                let mut bridled_count = 0;
   212→                let mut remaining_paces: Vec<(&String, &crate::jjrg_gallops::jjrg_Pace)> = Vec::new();
   213→                let mut first_remaining_pace: Option<(&String, &crate::jjrg_gallops::jjrg_Pace)> = None;
   214→
   215→                for coronet_key in &heat.order {
   216→                    if let Some(pace) = heat.paces.get(coronet_key) {
   217→                        if let Some(tack) = pace.tacks.first() {
   218→                            match tack.state {
   219→                                PaceState::Complete => complete_count += 1,
   220→                                PaceState::Abandoned => abandoned_count += 1,
   221→                                PaceState::Rough => {
   222→                                    rough_count += 1;
   223→                                    remaining_paces.push((coronet_key, pace));
   224→                                    if first_remaining_pace.is_none() {
   225→                                        first_remaining_pace = Some((coronet_key, pace));
   226→                                    }
   227→                                }
   228→                                PaceState::Bridled => {
   229→                                    bridled_count += 1;
   230→                                    remaining_paces.push((coronet_key, pace));
   231→                                    if first_remaining_pace.is_none() {
   232→                                        first_remaining_pace = Some((coronet_key, pace));
   233→                                    }
   234→                                }
   235→                            }
   236→                        }
   237→                    }
   238→                }
   239→
   240→                let status_str = match heat.status {
   241→                    HeatStatus::Racing => "racing",
   242→                    HeatStatus::Stabled => "stabled",
   243→                    HeatStatus::Retired => "retired",
   244→                };
   245→
   246→                let remaining_count = rough_count + bridled_count;
   247→
   248→                // Header line with heat info
   249→                println!("Heat: {} ({}) [{}]", heat.silks, heat_key, status_str);
   250→                println!("Progress: {} complete | {} abandoned | {} remaining ({} rough, {} bridled)",
   251→                    complete_count, abandoned_count, remaining_count, rough_count, bridled_count);
   252→                println!();
   253→
   254→                // Table with remaining paces
   255→                if !remaining_paces.is_empty() {
   256→                    // Set up table with column definitions
   257→                    let mut table = jjrp_Table::jjrp_new(vec![
   258→                        jjrp_Column::new("No", jjrp_Align::Right),
   259→                        jjrp_Column::new("State", jjrp_Align::Left),
   260→                        jjrp_Column::new("Pace", jjrp_Align::Left),
   261→                        jjrp_Column::new("₢Coronet", jjrp_Align::Left),
   262→                    ]);
   263→
   264→                    // Measure all rows to compute column widths
   265→                    for (idx, (coronet_key, pace)) in remaining_paces.iter().enumerate() {
   266→                        if let Some(tack) = pace.tacks.first() {
   267→                            let state_str = zjjrpd_pace_state_str(&tack.state);
   268→                            table.jjrp_measure(&[
   269→                                &(idx + 1).to_string(),
   270→                                state_str,
   271→                                &tack.silks,
   272→                                coronet_key,
   273→                            ]);
   274→                        }
   275→                    }
   276→
   277→                    // Print header and separator
   278→                    table.jjrp_print_header();
   279→                    table.jjrp_print_separator();
   280→
   281→                    // Print data rows
   282→                    for (idx, (coronet_key, pace)) in remaining_paces.iter().enumerate() {
   283→                        if let Some(tack) = pace.tacks.first() {
   284→                            let state_str = zjjrpd_pace_state_str(&tack.state);
   285→                            table.jjrp_print_row(&[
   286→                                &(idx + 1).to_string(),
   287→                                state_str,
   288→                                &tack.silks,
   289→                                coronet_key,
   290→                            ]);
   291→                        }
   292→                    }
   293→                    println!();
   294→                }
   295→
   296→                // Next up callout
   297→                if let Some((coronet_key, pace)) = first_remaining_pace {
   298→                    if let Some(tack) = pace.tacks.first() {
   299→                        let state_str = zjjrpd_pace_state_str(&tack.state);
   300→                        println!("Next: {} ({}) [{}]", tack.silks, coronet_key, state_str);
   301→                    }
   302→                }
   303→            } else {
   304→                // Column-justified list view (all paces)
   305→                // Set up table with column definitions
   306→                let mut table = jjrp_Table::jjrp_new(vec![
   307→                    jjrp_Column::new("No", jjrp_Align::Right),
   308→                    jjrp_Column::new("State", jjrp_Align::Left),
   309→                    jjrp_Column::new("Pace", jjrp_Align::Left),
   310→                    jjrp_Column::new("₢Coronet", jjrp_Align::Left),
   311→                ]);
   312→
   313→                // Measure all rows to compute column widths
   314→                let mut num = 0;
   315→                for coronet_key in &heat.order {
   316→                    if let Some(pace) = heat.paces.get(coronet_key) {
   317→                        if let Some(tack) = pace.tacks.first() {
   318→                            num += 1;
   319→                            let state_str = zjjrpd_pace_state_str(&tack.state);
   320→                            table.jjrp_measure(&[
   321→                                &num.to_string(),
   322→                                state_str,
   323→                                &tack.silks,
   324→                                coronet_key,
   325→                            ]);
   326→                        }
   327→                    }
   328→                }
   329→
   330→                // Print header and separator
   331→                table.jjrp_print_header();
   332→                table.jjrp_print_separator();
   333→
   334→                // Print data rows
   335→                let mut num = 0;
   336→                for coronet_key in &heat.order {
   337→                    if let Some(pace) = heat.paces.get(coronet_key) {
   338→                        if let Some(tack) = pace.tacks.first() {
   339→                            num += 1;
   340→                            let state_str = zjjrpd_pace_state_str(&tack.state);
   341→                            table.jjrp_print_row(&[
   342→                                &num.to_string(),
   343→                                state_str,
   344→                                &tack.silks,
   345→                                coronet_key,
   346→                            ]);
   347→                        }
   348→                    }
   349→                }
   350→            }
   351→        }
   352→    } else {
   353→        eprintln!("jjx_parade: error: target must be Firemark (2 chars) or Coronet (5 chars), got {} chars", target_str.len());
   354→        return 1;
   355→    }
   356→
   357→    0
   358→}
