   360→/// Build and print the file-touch bitmap for a heat.
   361→///
   362→/// Uses shared query routines from jjrq_query to get file touches,
   363→/// then formats as a bitmap with columns per pace and rows per file,
   364→/// grouped by identical touch patterns.
   365→fn zjjrpd_print_file_bitmap(firemark: &Firemark, heat: &Heat) -> i32 {
   366→    let touches = match jjrq_file_touches_for_heat(firemark.jjrf_as_str()) {
   367→        Ok(t) => t,
   368→        Err(e) => {
   369→            eprintln!("jjx_parade: error getting file touches: {}", e);
   370→            return 1;
   371→        }
   372→    };
   373→
   374→    let has_heat_level = !touches.heat_files.is_empty();
   375→
   376→    // Build pace columns: only paces with commits, in heat order
   377→    let mut pace_columns: Vec<(char, String, String)> = Vec::new();
   378→    for coronet_key in &heat.order {
   379→        if !touches.coronets_with_commits.contains(coronet_key) {
   380→            continue;
   381→        }
   382→        if let Some(pace) = heat.paces.get(coronet_key) {
   383→            if let Some(tack) = pace.tacks.first() {
   384→                let raw = coronet_key.strip_prefix('₢').unwrap_or(coronet_key);
   385→                if let Some(ch) = raw.chars().last() {
   386→                    pace_columns.push((ch, coronet_key.clone(), tack.silks.clone()));
   387→                }
   388→            }
   389→        }
   390→    }
   391→
   392→    // Map coronet_display -> column index
   393→    let mut coronet_to_col: BTreeMap<String, usize> = BTreeMap::new();
   394→    for (idx, (_, coronet_display, _)) in pace_columns.iter().enumerate() {
   395→        coronet_to_col.insert(coronet_display.clone(), idx);
   396→    }
   397→
   398→    let heat_col_idx = pace_columns.len();
   399→    let total_cols = if has_heat_level { heat_col_idx + 1 } else { heat_col_idx };
   400→
   401→    // Build file -> touch vector from the shared query result
   402→    let mut file_touches_map: BTreeMap<String, Vec<bool>> = BTreeMap::new();
   403→
   404→    for (coronet, files) in &touches.pace_files {
   405→        if let Some(&col_idx) = coronet_to_col.get(coronet) {
   406→            for filename in files {
   407→                let row = file_touches_map.entry(filename.clone()).or_insert_with(|| vec![false; total_cols]);
   408→                if col_idx < row.len() {
   409→                    row[col_idx] = true;
   410→                }
   411→            }
   412→        }
   413→    }
   414→
   415→    if has_heat_level {
   416→        for filename in &touches.heat_files {
   417→            let row = file_touches_map.entry(filename.clone()).or_insert_with(|| vec![false; total_cols]);
   418→            if heat_col_idx < row.len() {
   419→                row[heat_col_idx] = true;
   420→            }
   421→        }
   422→    }
   423→
   424→    if file_touches_map.is_empty() {
   425→        println!("File-touch bitmap: (no work file changes)");
   426→        return 0;
   427→    }
   428→
   429→    // Group files by identical touch pattern
   430→    let mut pattern_groups: BTreeMap<Vec<bool>, Vec<String>> = BTreeMap::new();
   431→    for (filename, pattern) in &file_touches_map {
   432→        pattern_groups.entry(pattern.clone()).or_default().push(filename.clone());
   433→    }
   434→
   435→    for files in pattern_groups.values_mut() {
   436→        files.sort();
   437→    }
   438→
   439→    // Print header
   440→    println!("File-touch bitmap (x = pace commit touched file):");
   441→    println!();
   442→
   443→    // Print vertical legend
   444→    for (i, (ch, _coronet, silks)) in pace_columns.iter().enumerate() {
   445→        println!("  {} {} {}", i + 1, ch, silks);
   446→    }
   447→    if has_heat_level {
   448→        println!("  {} * heat-level", pace_columns.len() + 1);
   449→    }
   450→    println!();
   451→
   452→    // Sort patterns: more touches first, then lexicographic
   453→    let mut sorted_patterns: Vec<(Vec<bool>, Vec<String>)> = pattern_groups.into_iter().collect();
   454→    sorted_patterns.sort_by(|(pat_a, _), (pat_b, _)| {
   455→        let count_a: usize = pat_a.iter().filter(|&&b| b).count();
   456→        let count_b: usize = pat_b.iter().filter(|&&b| b).count();
   457→        count_b.cmp(&count_a).then_with(|| pat_a.cmp(pat_b))
   458→    });
   459→
   460→    for (pattern, files) in &sorted_patterns {
   461→        let bitmap: String = pattern.iter().map(|&b| if b { 'x' } else { '·' }).collect();
   462→        println!("{} {}", bitmap, files.join(", "));
   463→    }
   464→
   465→    0
   466→}
   467→
   468→/// Helper to convert PaceState to display string
   469→pub(crate) fn zjjrpd_pace_state_str(state: &PaceState) -> &'static str {
   470→    match state {
   471→        PaceState::Rough => "rough",
   472→        PaceState::Bridled => "bridled",
   473→        PaceState::Complete => "complete",
   474→        PaceState::Abandoned => "abandoned",
   475→    }
   476→}
   477→
   478→/// Resolve the default heat (first racing heat) when no target is specified
   479→pub(crate) fn zjjrpd_resolve_default_heat(gallops: &Gallops) -> Result<String, String> {
   480→    for (heat_key, heat) in &gallops.heats {
   481→        if heat.status == HeatStatus::Racing {
   482→            return Ok(heat_key.clone());
   483→        }
   484→    }
   485→    Err("No racing heats found".to_string())
   486→}
